namespace sv_8ed2d365bc85497485fba2967e1d1117.Services;

public record TaskItem(int Id, string Title, string Assignee, string Priority, DateTime DueDate, string Status);

public interface ITaskService
{
    Task<List<TaskItem>> GetAllTasksAsync();
    Task<TaskItem> CreateTaskAsync(string title, string assignee, string priority, DateTime dueDate);
    Task UpdateTaskStatusAsync(int taskId, string newStatus);
}

@using sv_8ed2d365bc85497485fba2967e1d1117.Services

<div class="task-card">
    <h4>@Task.Title</h4>
    <p class="assignee">@Task.Assignee</p>
    <span class="priority-badge priority-@Task.Priority.ToLowerInvariant()">@Task.Priority</span>
    <span class="due-date">@Task.DueDate.ToString("MMM dd")</span>
    <div class="card-actions">
        @if (CanMoveLeft)
        {
            <button class="btn-move" @onclick="() => OnMoveLeft.InvokeAsync(Task)">◀ Move Left</button>
        }
        @if (CanMoveRight)
        {
            <button class="btn-move" @onclick="() => OnMoveRight.InvokeAsync(Task)">Move Right ▶</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveRight { get; set; }
}

@using sv_8ed2d365bc85497485fba2967e1d1117.Services

@if (!IsVisible)
{
    <button class="btn-add-task" @onclick="Show">+ Add Task</button>
}
else
{
    <div class="add-task-form">
        <input type="text" placeholder="Title" @bind="Title" />
        <input type="text" placeholder="Assignee" @bind="Assignee" />
        <select @bind="Priority">
            <option value="High">High</option>
            <option value="Medium">Medium</option>
            <option value="Low">Low</option>
        </select>
        <input type="date" @bind="DueDate" />
        <div class="form-actions">
            <button class="btn-save" @onclick="Save">Save</button>
            <button class="btn-cancel" @onclick="Cancel">Cancel</button>
        </div>
    </div>
}

@code {
    [Parameter, EditorRequired] public string DefaultStatus { get; set; } = "";
    [Parameter] public EventCallback<NewTaskRequest> OnTaskCreated { get; set; }

    private bool IsVisible;
    private string Title = "";
    private string Assignee = "";
    private string Priority = "Medium";
    private DateTime DueDate = DateTime.Today.AddDays(7);

    private void Show() => IsVisible = true;

    private void Cancel()
    {
        IsVisible = false;
        ResetForm();
    }

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(Title)) return;
        await OnTaskCreated.InvokeAsync(new NewTaskRequest(Title, Assignee, Priority, DueDate, DefaultStatus));
        IsVisible = false;
        ResetForm();
    }

    private void ResetForm()
    {
        Title = "";
        Assignee = "";
        Priority = "Medium";
        DueDate = DateTime.Today.AddDays(7);
    }

    public record NewTaskRequest(string Title, string Assignee, string Priority, DateTime DueDate, string Status);
}

@using sv_8ed2d365bc85497485fba2967e1d1117.Services
@using static AddTaskForm

<div class="board-column">
    <div class="column-header">
        <h3>@Title (@Tasks.Count)</h3>
    </div>
    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      CanMoveLeft="CanMoveLeft"
                      CanMoveRight="CanMoveRight"
                      OnMoveLeft="OnMoveLeft"
                      OnMoveRight="OnMoveRight" />
        }
    </div>
    <AddTaskForm DefaultStatus="@Status" OnTaskCreated="OnTaskCreated" />
</div>

@code {
    [Parameter, EditorRequired] public string Title { get; set; } = "";
    [Parameter, EditorRequired] public string Status { get; set; } = "";
    [Parameter] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveRight { get; set; }
    [Parameter] public EventCallback<NewTaskRequest> OnTaskCreated { get; set; }
}

@page "/board"
@rendermode InteractiveServer
@using sv_8ed2d365bc85497485fba2967e1d1117.Services
@using static AddTaskForm
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h2>Project Board</h2>

@if (isLoading)
{
    <p class="loading">Loading tasks…</p>
}
else if (errorMessage is not null)
{
    <div class="error-banner">
        <p>@errorMessage</p>
        <button @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats AllTasks="allTasks" />
    <BoardSearchBar OnSearchChanged="HandleSearchChanged" />

    <div class="board-columns">
        <BoardColumn Title="To Do" Status="To Do"
                     Tasks="@GetFiltered("To Do")"
                     CanMoveLeft="false" CanMoveRight="true"
                     OnMoveRight="@(t => MoveTask(t, "In Progress"))"
                     OnTaskCreated="HandleTaskCreated" />

        <BoardColumn Title="In Progress" Status="In Progress"
                     Tasks="@GetFiltered("In Progress")"
                     CanMoveLeft="true" CanMoveRight="true"
                     OnMoveLeft="@(t => MoveTask(t, "To Do"))"
                     OnMoveRight="@(t => MoveTask(t, "Done"))"
                     OnTaskCreated="HandleTaskCreated" />

        <BoardColumn Title="Done" Status="Done"
                     Tasks="@GetFiltered("Done")"
                     CanMoveLeft="true" CanMoveRight="false"
                     OnMoveLeft="@(t => MoveTask(t, "In Progress"))"
                     OnTaskCreated="HandleTaskCreated" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchTerm = "";
    private bool isLoading = true;
    private string? errorMessage;

    private static readonly string[] Columns = { "To Do", "In Progress", "Done" };

    protected override async Task OnInitializedAsync() => await LoadTasks();

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private void HandleSearchChanged(string term) => searchTerm = term;

    private List<TaskItem> GetFiltered(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchTerm))
            tasks = tasks.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));
        return tasks.ToList();
    }

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            allTasks = allTasks.Select(t => t.Id == task.Id ? t with { Status = newStatus } : t).ToList();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task HandleTaskCreated(NewTaskRequest req)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(req.Title, req.Assignee, req.Priority, req.DueDate);
            allTasks.Add(created);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

