+@page "/board"
+@rendermode InteractiveServer
+@using sv_8ed2d365bc85497485fba2967e1d1117.Services
+@using static AddTaskForm
+@inject ITaskService TaskService
+
+<PageTitle>Kanban Board</PageTitle>
+
+<h2>Project Board</h2>
+
+@if (isLoading)
+{
+    <p class="loading">Loading tasks…</p>
+}
+else if (errorMessage is not null)
+{
+    <div class="error-banner">
+        <p>@errorMessage</p>
+        <button @onclick="LoadTasks">Retry</button>
+    </div>
+}
+else
+{
+    <BoardStats AllTasks="allTasks" />
+    <BoardSearchBar OnSearchChanged="HandleSearchChanged" />
+
+    <div class="board-columns">
+        <BoardColumn Title="To Do" Status="To Do"
+                     Tasks="@GetFiltered("To Do")"
+                     CanMoveLeft="false" CanMoveRight="true"
+                     OnMoveRight="@(t => MoveTask(t, "In Progress"))"
+                     OnTaskCreated="HandleTaskCreated" />
+
+        <BoardColumn Title="In Progress" Status="In Progress"
+                     Tasks="@GetFiltered("In Progress")"
+                     CanMoveLeft="true" CanMoveRight="true"
+                     OnMoveLeft="@(t => MoveTask(t, "To Do"))"
+                     OnMoveRight="@(t => MoveTask(t, "Done"))"
+                     OnTaskCreated="HandleTaskCreated" />
+
+        <BoardColumn Title="Done" Status="Done"
+                     Tasks="@GetFiltered("Done")"
+                     CanMoveLeft="true" CanMoveRight="false"
+                     OnMoveLeft="@(t => MoveTask(t, "In Progress"))"
+                     OnTaskCreated="HandleTaskCreated" />
+    </div>
+}
+
+@code {
+    private List<TaskItem> allTasks = new();
+    private string searchTerm = "";
+    private bool isLoading = true;
+    private string? errorMessage;
+
+    private static readonly string[] Columns = { "To Do", "In Progress", "Done" };
+
+    protected override async Task OnInitializedAsync() => await LoadTasks();
+
+    private async Task LoadTasks()
+    {
+        isLoading = true;
+        errorMessage = null;
+        try
+        {
+            allTasks = await TaskService.GetAllTasksAsync();
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Failed to load tasks: {ex.Message}";
+        }
+        finally
+        {
+            isLoading = false;
+        }
+    }
+
+    private void HandleSearchChanged(string term) => searchTerm = term;
+
+    private List<TaskItem> GetFiltered(string status)
+    {
+        var tasks = allTasks.Where(t => t.Status == status);
+        if (!string.IsNullOrWhiteSpace(searchTerm))
+            tasks = tasks.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));
+        return tasks.ToList();
+    }
+
+    private async Task MoveTask(TaskItem task, string newStatus)
+    {
+        try
+        {
+            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
+            allTasks = allTasks.Select(t => t.Id == task.Id ? t with { Status = newStatus } : t).ToList();
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Failed to move task: {ex.Message}";
+        }
+    }
+
+    private async Task HandleTaskCreated(NewTaskRequest req)
+    {
+        try
+        {
+            var created = await TaskService.CreateTaskAsync(req.Title, req.Assignee, req.Priority, req.DueDate);
+            allTasks.Add(created);
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Failed to create task: {ex.Message}";
+        }
+    }
+}
+

